const requestSchema = z.object({
  figmaLink: z.string().trim().optional(),
  prompt: z.string().trim().min(3, "Describe what you want to build."),
  referenceImage: z
    .object({
      data: z.string().min(1),
      mimeType: z.string().min(1),
      name: z.string().min(1),
    })
    .optional(),
  currentGeneration: z
    .object({
      id: z.string().optional(),
      title: z.string().optional(),
      summary: z.string().optional(),
      prompt: z.string().optional(),
      previewHtml: z.string().optional(),
      previewCss: z.string().optional(),
      previewJs: z.string().optional(),
      files: z
        .array(
          z.object({
            path: z.string().min(1),
            content: z.string(),
          }),
        )
        .optional(),
    })
    .optional(),
});

const generationSchema = z.object({
  title: z.string().min(1),
  summary: z.string().min(1),
  previewHtml: z.string().min(1),
  previewCss: z.string().min(1),
  previewJs: z.string().optional().default(""),
  files: z
    .array(
      z.object({
        path: z.string().min(1),
        content: z.string(),
      }),
    )
    .min(1),
  notes: z.array(z.string()).optional().default([]),
});

const fileChangeSchema = z.object({
  path: z.string().min(1),
  action: z.enum(["created", "edited"]),
});

